mapper.select:
SELECT s.id, s.device_id, s.health_record_id, s.suggestion_date, s.maintenance_type, s.priority_level, s.suggested_start_date, s.suggested_end_date, s.related_spare_parts, s.estimated_cost, s.status, s.workorder_id, s.requisition_id, s.reason, s.reject_reason, s.handled_by, s.handled_at, s.created_at, s.updated_at, e.code AS device_code, e.name AS device_name, e.importance_level AS device_importance, h.health_score AS current_health_score, h.risk_level AS current_risk_level FROM biz_maintenance_suggestion s LEFT JOIN equipment e ON s.device_id = e.id LEFT JOIN ai_device_health h ON s.health_record_id = h.id WHERE 1=1
AND s.status = #{status}
AND s.priority_level = #{priorityLevel}
AND s.maintenance_type = #{maintenanceType}
AND e.code LIKE CONCAT('%', #{deviceCode}, '%')
ORDER BY FIELD(s.priority_level, 'HIGH', 'MEDIUM', 'LOW'), s.suggestion_date DESC LIMIT #{size} OFFSET #{offset}

SELECT COUNT(*)
FROM biz_maintenance_suggestion s
LEFT JOIN equipment e ON s.device_id = e.id
WHERE 1=1

    AND s.status = #{status}


    AND s.priority_level = #{priorityLevel}


    AND s.maintenance_type = #{maintenanceType}


    AND e.code LIKE CONCAT('%', #{deviceCode}, '%')

mapper.delete:
DELETE FROM biz_maintenance_suggestion
WHERE status = 'COMPLETED'
  AND suggestion_date < #{beforeDate}
